	}
	return;
}
void dfs(int x, int fa, int len, int len1)
{
	if (len1 == 1) // g(cur,x) 为 1，不满足条件
		return;
	ans = max(ans, maxi + len - 1);
	tmp[++tot] = len;
	for (auto& nxt : nbr[x])
		if (!del[nxt] && nxt != fa)
			dfs(nxt, x, len + 1, __gcd(len1, a[nxt]));
	return;
}
void work(int x)
{
	for (auto& j : e[a[x]])
		if (!(a[x] % b[j])) // 枚举质因数，但是这一行多此一举
		{
			maxi = 1;
			for (auto& nxt : nbr[x])
				if (!del[nxt] && __gcd(__gcd(a[x], a[nxt]), b[j]) == b[j]) // 只考虑该质因数相同的子树
				{
					int tmp1 = tot;
					dfs(nxt, x, 2, b[j]);
					for (int i = tmp1 + 1; i <= tot; i++)
						maxi = max(maxi, tmp[i]);
				}
			tot = 0;
		}
	del[x] = true;
	for (auto& nxt : nbr[x])
		if (!del[nxt])
		{
			n = sz[nxt];
			ctr = 0;
			get_ctr(nxt, 0);
			work(ctr);
		}
	return;
}
signed main()
{
	ios::sync_with_stdio(0);
	cin.tie(0), cout.tie(0);
	for (int i = 2; i <= 2e5; i++)
	{
		if (!vis[i])
		{
			b[++c] = i;
			for (int j = i; j <= 2e5; j += i)
				e[j].push_back(c);
		}
		for (int j = 1; j <= c; j++)
		{
			if (i * b[j] > 2e5)
				break;
			vis[i * b[j]] = true;
			if (!(i % b[j]))
				break;
		}
	}
	cin >> n;
	for (int i = 1; i <= n; i++)
		cin >> a[i], ans = max<int>(ans, a[i] > 1);
	for (int i = 1; i < n; i++)
	{
		int x, y;
		cin >> x >> y;
		nbr[x].push_back(y);
		nbr[y].push_back(x);
	}
	get_ctr(1, 0);
	work(ctr);
	cout << ans;
	return 0;
}
