### 洛谷 P2634

[P2634 \[国家集训队\] 聪聪可可](https://www.luogu.com.cn/problem/P2634)

模板题，注意答案需要化简。

```cpp
#include<bits/stdc++.h>
typedef int int32;
#define int long long
using namespace std;
const int N = 2e4 + 5;
int n, sz[N], cnt[N], tmp[N], tot, ctr, ans;
bitset<N>del;
vector<pair<int, int>>nbr[N];
void get_ctr(int x, int fa)
{
	sz[x] = 1;
	int maxi = 0;
	for (auto& y : nbr[x])
	{
		auto& nxt = y.first, & w = y.second;
		if (!del[nxt] && nxt != fa)
		{
			get_ctr(nxt, x);
			if (ctr)
				return;
			maxi = max(maxi, sz[nxt]);
			sz[x] += sz[nxt];
		}
	}
	maxi = max(maxi, n - sz[x]);
	if (maxi <= n / 2)
	{
		ctr = x;
		sz[fa] = n - sz[x];
	}
	return;
}
void dfs(int x, int fa, int len)
{
	ans += cnt[(3 - len) % 3] + !len;
	tmp[++tot] = len;
	for (auto& y : nbr[x])
	{
		auto& nxt = y.first, & w = y.second;
		if (!del[nxt] && nxt != fa)
			dfs(nxt, x, (len + w) % 3);
	}
	return;
}
void work(int x)
{
	for (auto& y : nbr[x])
	{
		auto& nxt = y.first, & w = y.second;
		if (!del[nxt])
		{
			int tmp1 = tot;
			dfs(nxt, x, w % 3);
			for (int i = tmp1 + 1; i <= tot; i++)
				cnt[tmp[i]]++;
		}
	}
	for (int i = 1; i <= tot; i++)
		cnt[tmp[i]]--;
	tot = 0;
	del[x] = true;
	for (auto& y : nbr[x])
	{
		auto& nxt = y.first, & w = y.second;
		if (!del[nxt])
		{
			n = sz[nxt];
			ctr = 0;
			get_ctr(nxt, 0);
			work(ctr);
		}
	}
	return;
}
signed main()
{
	ios::sync_with_stdio(0);
	cin.tie(0), cout.tie(0);
	cin >> n;
	int m = n;
	for (int i = 1; i < n; i++)
	{
		int x, y, z;
		cin >> x >> y >> z;
		nbr[x].push_back({ y,z });
		nbr[y].push_back({ x,z });
	}
	get_ctr(1, 0);
	work(ctr);
	int tmp = __gcd(ans * 2 + m, m * m);
	cout << (ans * 2 + m) / tmp << '/' << m * m / tmp;
	return 0;
}
