### 洛谷 P4178
[P4178 Tree](https://www.luogu.com.cn/problem/P4178)

统计答案时记得因为是小于等于 $m$（题目中 $k$）的，所以要查询 $m-{len}+1$ 并且加一。

```cpp
void update(int x, int k)
{
	while (x <= m + 1)
	{
		tree[x] += k;
		x += lowbit(x);
	}
	return;
}
int query(int x)
{
	int sum = 0;
	while (x)
	{
		sum += tree[x];
		x -= lowbit(x);
	}
	return sum;
}
void dfs(int x, int fa, int len)
{
	if (len > m)
		return;
	ans += query(m - len + 1) + 1;
	tmp[++tot] = len;
	for (auto& y : nbr[x])
	{
		auto& nxt = y.first, & w = y.second;
		if (!del[nxt] && nxt != fa)
			dfs(nxt, x, len + w);
	}
	return;
}
void work(int x)
{
	for (auto& y : nbr[x])
	{
		auto& nxt = y.first, & w = y.second;
		if (!del[nxt])
		{
			int tmp1 = tot;
			dfs(nxt, x, w);
			for (int i = tmp1 + 1; i <= tot; i++)
				update(tmp[i] + 1, 1);
		}
	}
	for (int i = 1; i <= tot; i++)
		update(tmp[i] + 1, -1);
	tot = 0;
	del[x] = true;
	for (auto& y : nbr[x])
	{
		auto& nxt = y.first, & w = y.second;
		if (!del[nxt])
		{
			n = sz[nxt];
			ctr = 0;
			get_ctr(nxt, 0);
			work(ctr);
		}
	}
	return;
}
